<script lang="ts">import { formatCurrency } from '$lib/utils/format'; import { invoiceStatusLabel } from '$lib/utils/format'; let { data } = $props();</script>
<section class="card no-print flex flex-wrap items-center justify-between gap-4 p-6"><div><p class="text-sm font-medium text-brand-600">Invoices</p><h1 class="mt-2 text-3xl font-semibold text-slate-900">Track drafts, issued invoices, and payments</h1></div><form method="POST" action="?/create"><button class="btn-primary" data-testid="invoice-create" type="submit">Create invoice</button></form></section>
<section class="card no-print p-6"><form method="GET" class="flex flex-col gap-3 md:flex-row"><input class="input" name="q" placeholder="Search invoice number or customer" value={data.query} /><button class="btn-secondary md:w-max" type="submit">Filter</button></form></section>
<section class="card overflow-hidden p-0">{#if data.invoices.length === 0}<div class="p-8 text-center text-sm text-slate-500">No invoices yet. Create one to start billing.</div>{:else}<div class="overflow-x-auto"><table class="min-w-full text-left text-sm"><thead class="bg-slate-50 text-slate-500"><tr><th class="px-6 py-4 font-medium">Invoice</th><th class="px-6 py-4 font-medium">Customer</th><th class="px-6 py-4 font-medium">Status</th><th class="px-6 py-4 font-medium">Due date</th><th class="px-6 py-4 font-medium">Total</th><th class="px-6 py-4 font-medium">Actions</th></tr></thead><tbody>{#each data.invoices as invoice}<tr class="border-t border-slate-100"><td class="px-6 py-4"><a class="font-medium text-slate-900" href={`/app/invoices/${invoice.id}`}>{invoice.invoiceNumber}</a></td><td class="px-6 py-4 text-slate-600">{invoice.customerName}</td><td class="px-6 py-4"><span class={`badge badge-${invoice.status}`}>{invoiceStatusLabel(invoice.status)}</span></td><td class="px-6 py-4 text-slate-600">{invoice.dueDate}</td><td class="px-6 py-4 font-medium text-slate-900">{formatCurrency(invoice.totalAmount, invoice.currency)}</td><td class="px-6 py-4"><div class="flex flex-wrap gap-2"><a class="btn-secondary" href={`/app/invoices/${invoice.id}`}>Open</a><form method="POST" action="?/duplicate"><input type="hidden" name="id" value={invoice.id} /><button class="btn-secondary" type="submit">Duplicate</button></form><form method="POST" action="?/delete"><input type="hidden" name="id" value={invoice.id} /><button class="btn-danger" type="submit">Delete</button></form></div></td></tr>{/each}</tbody></table></div>{/if}</section>
